const sym = String(($json.query && $json.query.symbol) || 'BTC').replace('USDT','').toUpperCase();
const k = await this.helpers.httpRequest({ url: `https://api.binance.com/api/v3/klines?symbol=${sym}USDT&interval=1d&limit=1`, json: true });
const c = k[0];
const quoteVol = parseFloat(c[7]);
const takerBuy = parseFloat(c[10]);
const netInflow = takerBuy - (quoteVol - takerBuy);
const buyPct = quoteVol > 0 ? (takerBuy / quoteVol * 100) : 0;
const open = parseFloat(c[1]); const close = parseFloat(c[4]);
const changePct = open ? ((close - open) / open * 100) : 0;
return [{ json: { symbol: sym, entrada_liquida_usdt: Math.round(netInflow), pct_compra: Number(buyPct.toFixed(1)),
  variacao_pct: Number(changePct.toFixed(2)), volume_total_usdt: Math.round(quoteVol), periodo: 'candle diario UTC' } }];
